SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Condition' AND in_valueset(r.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.464.1003.1165') AND list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-condition-problems-health-concerns')
),
"Procedure: Hospice Care Ambulatory" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Procedure' AND in_valueset(r.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1584') AND (fhirpath_text(r.resource, 'status') IS NULL OR fhirpath_text(r.resource, 'status') != 'not-done') AND (json_extract(r.resource, '$.meta.profile') IS NULL OR NOT list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-procedurenotdone'))
),
"Observation: Hospice care [Minimum Data Set]" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Observation' AND fhirpath_bool(r.resource, 'code.coding.where(system=''http://loinc.org'' and code=''45755-6'').exists()')
),
"ServiceRequest: Hospice Care Ambulatory" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'ServiceRequest' AND in_valueset(r.resource, 'code', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.526.3.1584') AND (json_extract(r.resource, '$.meta.profile') IS NULL OR NOT list_contains(from_json(json_extract(r.resource, '$.meta.profile'), '["VARCHAR"]'), 'http://hl7.org/fhir/us/qicore/StructureDefinition/qicore-servicenotrequested'))
),
"Encounter: Hospice Encounter" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Encounter' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.464.1003.1003')
),
"Encounter: Encounter Inpatient" AS (
SELECT DISTINCT r.patient_ref AS patient_id, r.resource FROM resources r WHERE r.resourceType = 'Encounter' AND in_valueset(r.resource, 'type', 'http://cts.nlm.nih.gov/fhir/ValueSet/2.16.840.1.113883.3.666.5.307')
),
"Hospice.Has Hospice Services" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Encounter Inpatient" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS InpatientEncounter WHERE InpatientEncounter.patient_id = p.patient_id AND (fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428361000124107'').exists()') OR fhirpath_bool(InpatientEncounter.resource, 'hospitalization.dischargeDisposition.coding.where(system=''http://snomed.info/sct'' and code=''428371000124100'').exists()')) AND CAST(intervalEnd(fhirpath_text(InpatientEncounter.resource, 'period')) AS DATE) BETWEEN CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE) AND COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Encounter: Hospice Encounter" WHERE fhirpath_text(resource, 'status') IN ('finished')) AS HospiceEncounter WHERE HospiceEncounter.patient_id = p.patient_id AND CAST(intervalStart(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(fhirpath_text(HospiceEncounter.resource, 'period')) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Observation: Hospice care [Minimum Data Set]" WHERE fhirpath_text(resource, 'status') IN ('final', 'amended', 'corrected')) AS HospiceAssessment WHERE HospiceAssessment.patient_id = p.patient_id AND fhirpath_bool(HospiceAssessment.resource, 'value.coding.where(system=''http://snomed.info/sct'' and code=''373066001'').exists()') AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceAssessment.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospiceAssessment.resource, 'effective')), '{') THEN fhirpath_text(HospiceAssessment.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(HospiceAssessment.resource, 'effective'), fhirpath_text(HospiceAssessment.resource, 'effective'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "ServiceRequest: Hospice Care Ambulatory" WHERE fhirpath_text(resource, 'status') IN ('active', 'completed') AND fhirpath_text(resource, 'intent') IN ('order', 'original-order', 'reflex-order', 'filler-order', 'instance-order')) AS HospiceOrder WHERE HospiceOrder.patient_id = p.patient_id AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(fhirpath_text(HospiceOrder.resource, 'authoredOn') AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Procedure: Hospice Care Ambulatory" WHERE fhirpath_text(resource, 'status') IN ('completed')) AS HospicePerformed WHERE HospicePerformed.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospicePerformed.resource, 'performed') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(HospicePerformed.resource, 'performed')), '{') THEN fhirpath_text(HospicePerformed.resource, 'performed') ELSE intervalFromBounds(fhirpath_text(HospicePerformed.resource, 'performed'), fhirpath_text(HospicePerformed.resource, 'performed'), TRUE, TRUE) END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE)) OR EXISTS (SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Hospice Diagnosis (qicore-condition-encounter-diagnosis)") AS _union WHERE fhirpath_text(resource, 'verificationStatus') IS NULL OR fhirpath_text(resource, 'verificationStatus') IN ('confirmed', 'unconfirmed', 'provisional', 'differential')) AS HospiceCareDiagnosis WHERE HospiceCareDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) <= COALESCE(CAST(intervalEnd(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE), CAST('9999-12-31' AS DATE)) AND COALESCE(CAST(intervalEnd(CASE WHEN fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), fhirpath_text(HospiceCareDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HospiceCareDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HospiceCareDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HospiceCareDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HospiceCareDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE), CAST('9999-12-31' AS DATE)) >= CAST(intervalStart(intervalFromBounds(CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS VARCHAR), CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS VARCHAR), TRUE, TRUE)) AS DATE))
),
"SDE.SDE Ethnicity" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-ethnicity'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_E -> json_object('codes', "Distinct"(list_concat([fhirpath_text(_lt_E, 'ombCategory')], fhirpath_text(_lt_E, 'detailed'))), 'display', fhirpath_text(_lt_E, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Payer" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('code', Payer.type, 'period', fhirpath_text(Payer.resource, 'period')) AS _resource_data FROM "Coverage: Payer Type" AS Payer) AS _inner
),
"SDE.SDE Race" AS (
SELECT p.patient_id, list_transform(from_json(fhirpath((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-race'').extension.where(url=''ombCategory'').valueCoding.code'), '["VARCHAR"]'), _lt_R -> json_object('codes', CASE WHEN fhirpath_text(_lt_R, 'ombCategory') IS NOT NULL  AND fhirpath_text(_lt_R, 'detailed') IS NOT NULL  THEN "Distinct"(jsonConcat(fhirpath_text(_lt_R, 'ombCategory'), fhirpath_text(_lt_R, 'detailed'))) ELSE NULL END, 'display', fhirpath_text(_lt_R, 'text'))) AS resource FROM _patients AS p
),
"SDE.SDE Sex" AS (
SELECT p.patient_id, (SELECT CASE WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248153007' THEN 'http://snomed.info/sct|248153007' WHEN fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'extension.where(url=''http://hl7.org/fhir/us/core/StructureDefinition/us-core-sex'').valueCode') = '248152002' THEN 'http://snomed.info/sct|248152002' ELSE NULL END) AS value FROM _patients AS p
),
"Date of First Birthday" AS (
SELECT p.patient_id, dateAddQuantity(CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'birthDate') AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS value FROM _patients AS p
),
"Date of Second Birthday" AS (
SELECT p.patient_id, dateAddQuantity(CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'birthDate') AS VARCHAR), '{"value": 2.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS value FROM _patients AS p
),
"Date of First Birthday to Date of Second Birthday" AS (
SELECT p.patient_id, intervalFromBounds(CAST((SELECT sub.value FROM "Date of First Birthday" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), CAST((SELECT sub.value FROM "Date of Second Birthday" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), TRUE, TRUE) AS value FROM _patients AS p
),
"First Two Years" AS (
SELECT p.patient_id, intervalFromBounds(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'birthDate'), CAST((SELECT sub.value FROM "Date of Second Birthday" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), TRUE, TRUE) AS value FROM _patients AS p
),
"DTaP Numerator Inclusion Conditions" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Anaphylactic Reaction to DTaP Vaccine (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Anaphylactic Reaction to DTaP Vaccine (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Encephalitis Due to Diphtheria, Tetanus or Pertussis Vaccine (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Encephalitis Due to Diphtheria, Tetanus or Pertussis Vaccine (qicore-condition-problems-health-concerns)") AS DTaPConditions WHERE CAST(intervalStart(CASE WHEN fhirpath_text(DTaPConditions.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')), fhirpath_text(DTaPConditions.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(DTaPConditions.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = DTaPConditions.patient_id LIMIT 1)) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(DTaPConditions.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')), fhirpath_text(DTaPConditions.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(DTaPConditions.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(DTaPConditions.resource, 'onsetDateTime'), fhirpath_text(DTaPConditions.resource, 'onsetPeriod.start'), fhirpath_text(DTaPConditions.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = DTaPConditions.patient_id LIMIT 1)) AS DATE)
),
"Has HIV" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: HIV (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: HIV (qicore-condition-problems-health-concerns)") AS HIVDiagnosis WHERE HIVDiagnosis.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(HIVDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')), fhirpath_text(HIVDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HIVDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(HIVDiagnosis.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')), fhirpath_text(HIVDiagnosis.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(HIVDiagnosis.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(HIVDiagnosis.resource, 'onsetDateTime'), fhirpath_text(HIVDiagnosis.resource, 'onsetPeriod.start'), fhirpath_text(HIVDiagnosis.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE))
),
"Has Immunodeficiency" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT * FROM (SELECT patient_id, resource FROM "Condition: Disorders of the Immune System (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Disorders of the Immune System (qicore-condition-problems-health-concerns)") AS ImmuneDisorder WHERE ImmuneDisorder.patient_id = p.patient_id AND CAST(intervalStart(CASE WHEN fhirpath_text(ImmuneDisorder.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')), fhirpath_text(ImmuneDisorder.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ImmuneDisorder.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(ImmuneDisorder.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')), fhirpath_text(ImmuneDisorder.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(ImmuneDisorder.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(ImmuneDisorder.resource, 'onsetDateTime'), fhirpath_text(ImmuneDisorder.resource, 'onsetPeriod.start'), fhirpath_text(ImmuneDisorder.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1)) AS DATE))
),
