th_text(PolioConditions.resource, 'onsetPeriod.start'), fhirpath_text(PolioConditions.resource, 'recordedDate')), fhirpath_text(PolioConditions.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(PolioConditions.resource, 'onsetDateTime'), fhirpath_text(PolioConditions.resource, 'onsetPeriod.start'), fhirpath_text(PolioConditions.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(PolioConditions.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(PolioConditions.resource, 'onsetDateTime'), fhirpath_text(PolioConditions.resource, 'onsetPeriod.start'), fhirpath_text(PolioConditions.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(PolioConditions.resource, 'onsetDateTime'), fhirpath_text(PolioConditions.resource, 'onsetPeriod.start'), fhirpath_text(PolioConditions.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = PolioConditions.patient_id LIMIT 1)) AS DATE)
