"Qualifying Encounters" AS (
SELECT * FROM (SELECT patient_id, resource FROM (SELECT patient_id, resource FROM "Encounter: Office Visit" UNION SELECT patient_id, resource FROM "Encounter: Home Healthcare Services" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care, Established Office Visit, 0 to 17" UNION SELECT patient_id, resource FROM "Encounter: Preventive Care Services, Initial Office Visit, 0 to 17" UNION (SELECT patient_id, resource FROM "Encounter" AS E WHERE fhirpath_bool(E.resource, 'type.coding.where(system=''http://www.ama-assn.org/go/cpt'' and code=''99211'').exists()')) UNION SELECT patient_id, resource FROM "Encounter: Virtual Encounter" UNION SELECT patient_id, resource FROM "Encounter: Telephone Visits") AS _union WHERE fhirpath_text(resource, 'status') IN ('finished')) AS ValidEncounters WHERE CAST(intervalStart(CASE WHEN fhirpath_text(ValidEncounters.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ValidEncounters.resource, 'period')), '{') THEN fhirpath_text(ValidEncounters.resource, 'period') ELSE intervalFromBounds(fhirpath_text(ValidEncounters.resource, 'period'), fhirpath_text(ValidEncounters.resource, 'period'), TRUE, TRUE) END) AS DATE) >= CAST(CAST('2026-01-01T00:00:00.000' AS TIMESTAMP) AS DATE) AND CAST(intervalEnd(CASE WHEN fhirpath_text(ValidEncounters.resource, 'period') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(ValidEncounters.resource, 'period')), '{') THEN fhirpath_text(ValidEncounters.resource, 'period') ELSE intervalFromBounds(fhirpath_text(ValidEncounters.resource, 'period'), fhirpath_text(ValidEncounters.resource, 'period'), TRUE, TRUE) END) AS DATE) <= CAST(CAST('2026-12-31T23:59:59.999' AS TIMESTAMP) AS DATE)
),
"Initial Population" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXTRACT(YEAR FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) - EXTRACT(YEAR FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) - CASE WHEN EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) OR EXTRACT(MONTH FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) = EXTRACT(MONTH FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) AND EXTRACT(DAY FROM CAST('2026-12-31T23:59:59.999' AS TIMESTAMP)) < EXTRACT(DAY FROM (SELECT _pd.birth_date FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1)) THEN 1 ELSE 0 END = 2 AND EXISTS (SELECT 1 FROM "Qualifying Encounters" AS sub WHERE sub.patient_id = p.patient_id)
),
"Denominator" AS (
SELECT * FROM "Initial Population"
),
