"Vaccine Administration Interval - 180 Days up to 2 Years Old" AS (
SELECT p.patient_id, intervalFromBounds(CAST(dateAddQuantity(CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'birthDate') AS VARCHAR), '{"value": 180.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST((SELECT sub.value FROM "Date of Second Birthday" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), TRUE, TRUE) AS value FROM _patients AS p
),
"Vaccine Administration Interval - 42 Days up to 2 Years Old" AS (
SELECT p.patient_id, intervalFromBounds(CAST(dateAddQuantity(CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = p.patient_id LIMIT 1), 'birthDate') AS VARCHAR), '{"value": 42.0, "unit": "day", "system": "http://unitsofmeasure.org"}') AS VARCHAR), CAST((SELECT sub.value FROM "Date of Second Birthday" AS sub WHERE sub.patient_id = p.patient_id LIMIT 1) AS VARCHAR), TRUE, TRUE) AS value FROM _patients AS p
),
