cinations.value IS NULL THEN NULL WHEN starts_with(LTRIM(RotavirusVaccinations.value), '{') THEN RotavirusVaccinations.value ELSE intervalFromBounds(CAST(RotavirusVaccinations.value AS VARCHAR), CAST(RotavirusVaccinations.value AS VARCHAR), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN RotavirusVaccinations.value IS NULL THEN NULL WHEN starts_with(LTRIM(RotavirusVaccinations.value), '{') THEN RotavirusVaccinations.value ELSE intervalFromBounds(CAST(RotavirusVaccinations.value AS VARCHAR), CAST(RotavirusVaccinations.value AS VARCHAR), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN RotavirusVaccinations.value IS NULL THEN NULL WHEN starts_with(LTRIM(RotavirusVaccinations.value), '{') THEN RotavirusVaccinations.value ELSE intervalFromBounds(CAST(RotavirusVaccinations.value AS VARCHAR), CAST(RotavirusVaccinations.value AS VARCHAR), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN RotavirusVaccinations.value IS NULL THEN NULL WHEN starts_with(LTRIM(RotavirusVaccinations.value), '{') THEN RotavirusVaccinations.value ELSE intervalFromBounds(CAST(RotavirusVaccinations.value AS VARCHAR), CAST(RotavirusVaccinations.value AS VARCHAR), TRUE, TRUE) END) END) AS _val FROM "Rotavirus 2 or 3 Dose Immunizations" AS RotavirusVaccinations WHERE RotavirusVaccinations.patient_id = RotavirusImmunization.patient_id) AS _agg) >= 2))
),
