tion3.value ELSE intervalFromBounds(CAST(PolioVaccination3.value AS VARCHAR), CAST(PolioVaccination3.value AS VARCHAR), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN PolioVaccination3.value IS NULL THEN NULL WHEN starts_with(LTRIM(PolioVaccination3.value), '{') THEN PolioVaccination3.value ELSE intervalFromBounds(CAST(PolioVaccination3.value AS VARCHAR), CAST(PolioVaccination3.value AS VARCHAR), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN PolioVaccination3.value IS NULL THEN NULL WHEN starts_with(LTRIM(PolioVaccination3.value), '{') THEN PolioVaccination3.value ELSE intervalFromBounds(CAST(PolioVaccination3.value AS VARCHAR), CAST(PolioVaccination3.value AS VARCHAR), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN PolioVaccination3.value IS NULL THEN NULL WHEN starts_with(LTRIM(PolioVaccination3.value), '{') THEN PolioVaccination3.value ELSE intervalFromBounds(CAST(PolioVaccination3.value AS VARCHAR), CAST(PolioVaccination3.value AS VARCHAR), TRUE, TRUE) END) END AS TIMESTAMP) >= CAST(CASE WHEN NOT (intervalStart(CASE WHEN PolioVaccination2.value IS NULL THEN NULL WHEN starts_with(LTRIM(PolioVaccination2.value), '{') THEN PolioVaccination2.value ELSE intervalFromBounds(CAST(PolioVaccination2.value AS VARCHAR), CAST(PolioVaccination2.value AS VARCHAR), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN PolioVaccination2.value IS NULL THEN NULL WHEN starts_with(LTRIM(PolioVaccination2.value), '{') THEN PolioVaccination2.value ELSE intervalFromBounds(CAST(PolioVaccination2.value AS VARCHAR), CAST(PolioVaccination2.value AS VARCHAR), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN PolioVaccination2.value IS NULL THEN NULL WHEN starts_with(LTRIM(PolioVaccination2.value), '{') THEN PolioVaccination2.value ELSE intervalFromBounds(CAST(PolioVaccination2.value AS VARCHAR), CAST(PolioVaccination2.value AS VARCHAR), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN PolioVaccination2.value IS NULL THEN NULL WHEN starts_with(LTRIM(PolioVaccination2.value), '{') THEN PolioVaccination2.value ELSE intervalFromBounds(CAST(PolioVaccination2.value AS VARCHAR), CAST(PolioVaccination2.value AS VARCHAR), TRUE, TRUE) END) END AS TIMESTAMP) + INTERVAL '1 day' AND PolioVaccination2.patient_id = PolioVaccination1.patient_id AND PolioVaccination3.patient_id = PolioVaccination1.patient_id
),
