rts_with(LTRIM(FluVaccination2.value), '{') THEN FluVaccination2.value ELSE intervalFromBounds(CAST(FluVaccination2.value AS VARCHAR), CAST(FluVaccination2.value AS VARCHAR), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN FluVaccination2.value IS NULL THEN NULL WHEN starts_with(LTRIM(FluVaccination2.value), '{') THEN FluVaccination2.value ELSE intervalFromBounds(CAST(FluVaccination2.value AS VARCHAR), CAST(FluVaccination2.value AS VARCHAR), TRUE, TRUE) END) END AS TIMESTAMP) >= CAST(CASE WHEN NOT (intervalStart(CASE WHEN FluVaccination1.value IS NULL THEN NULL WHEN starts_with(LTRIM(FluVaccination1.value), '{') THEN FluVaccination1.value ELSE intervalFromBounds(CAST(FluVaccination1.value AS VARCHAR), CAST(FluVaccination1.value AS VARCHAR), TRUE, TRUE) END) IS NULL OR intervalStart(CASE WHEN FluVaccination1.value IS NULL THEN NULL WHEN starts_with(LTRIM(FluVaccination1.value), '{') THEN FluVaccination1.value ELSE intervalFromBounds(CAST(FluVaccination1.value AS VARCHAR), CAST(FluVaccination1.value AS VARCHAR), TRUE, TRUE) END) = '0001-01-01 00:00:00') THEN intervalStart(CASE WHEN FluVaccination1.value IS NULL THEN NULL WHEN starts_with(LTRIM(FluVaccination1.value), '{') THEN FluVaccination1.value ELSE intervalFromBounds(CAST(FluVaccination1.value AS VARCHAR), CAST(FluVaccination1.value AS VARCHAR), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN FluVaccination1.value IS NULL THEN NULL WHEN starts_with(LTRIM(FluVaccination1.value), '{') THEN FluVaccination1.value ELSE intervalFromBounds(CAST(FluVaccination1.value AS VARCHAR), CAST(FluVaccination1.value AS VARCHAR), TRUE, TRUE) END) END AS TIMESTAMP) + INTERVAL '1 day' AND FluVaccination2.patient_id = FluVaccination1.patient_id
),
"Two Influenza Vaccinations Including One LAIV Vaccination" AS (
SELECT p.patient_id FROM _patients AS p WHERE EXISTS (SELECT 1 FROM "LAIV Vaccinations" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Influenza Immunizations or Procedures" AS sub WHERE sub.patient_id = p.patient_id)
),
"Varicella Zoster Numerator Inclusion Conditions" AS (
SELECT * FROM (SELECT patient_id, resource FROM "Condition: Varicella Zoster (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Varicella Zoster (qicore-condition-problems-health-concerns)" UNION SELECT patient_id, resource FROM "Condition: Anaphylaxis caused by vaccine containing Human alphaherpesvirus 3 antigen (disorder) (qicore-condition-encounter-diagnosis)" UNION SELECT patient_id, resource FROM "Condition: Anaphylaxis caused by vaccine containing Human alphaherpesvirus 3 antigen (disorder) (qicore-condition-problems-health-concerns)") AS VaricellaZoster WHERE CAST(intervalStart(CASE WHEN fhirpath_text(VaricellaZoster.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')), fhirpath_text(VaricellaZoster.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(VaricellaZoster.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) >= CAST(intervalStart((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = VaricellaZoster.patient_id LIMIT 1)) AS DATE) AND CAST(intervalStart(CASE WHEN fhirpath_text(VaricellaZoster.resource, 'abatementDateTime') IS NOT NULL THEN intervalFromBounds(COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')), fhirpath_text(VaricellaZoster.resource, 'abatementDateTime'), TRUE, TRUE) WHEN COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')) IS NOT NULL THEN CASE WHEN fhirpath_bool(VaricellaZoster.resource, 'clinicalStatus.coding.where(code=''active'' or code=''recurrence'' or code=''relapse'').exists()') THEN intervalFromBounds(COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, TRUE) ELSE intervalFromBounds(COALESCE(fhirpath_text(VaricellaZoster.resource, 'onsetDateTime'), fhirpath_text(VaricellaZoster.resource, 'onsetPeriod.start'), fhirpath_text(VaricellaZoster.resource, 'recordedDate')), CAST(NULL AS VARCHAR), TRUE, FALSE) END ELSE NULL END) AS DATE) < CAST(intervalEnd((SELECT sub.value FROM "First Two Years" AS sub WHERE sub.patient_id = VaricellaZoster.patient_id LIMIT 1)) AS DATE)
),
"Numerator" AS (
SELECT p.patient_id FROM _patients AS p WHERE (EXISTS (SELECT 1 FROM "Four DTaP Vaccinations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "DTaP Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "Three Polio Vaccinations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Polio Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "One MMR Vaccination" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "MMR Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Measles Indicators" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Mumps Indicators" AS sub WHERE sub.patient_id = p.patient_id) AND EXISTS (SELECT 1 FROM "Rubella Indicators" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "Has Appropriate Number of Hib Immunizations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Hib Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "Three Hepatitis B Vaccinations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Meets HepB Vaccination Requirement" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Hepatitis B Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "One Chicken Pox Vaccination" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Varicella Zoster Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "Four Pneumococcal Conjugate Vaccinations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Pneumococcal Conjugate Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "One Hepatitis A Vaccinations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Hepatitis A Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "Has Appropriate Number of Rotavirus Immunizations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Rotavirus Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id)) AND (EXISTS (SELECT 1 FROM "Two Influenza Vaccinations" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Two Influenza Vaccinations Including One LAIV Vaccination" AS sub WHERE sub.patient_id = p.patient_id) OR EXISTS (SELECT 1 FROM "Influenza Numerator Inclusion Conditions" AS sub WHERE sub.patient_id = p.patient_id))
)
SELECT p.patient_id, (SELECT CASE WHEN "Initial Population".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Initial Population", (SELECT CASE WHEN "Denominator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Denominator, (SELECT CASE WHEN "Denominator Exclusions".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS "Denominator Exclusions", (SELECT CASE WHEN "Numerator".patient_id IS NOT NULL THEN TRUE ELSE FALSE END) AS Numerator FROM _patients p LEFT JOIN "Initial Population" ON p.patient_id = "Initial Population".patient_id LEFT JOIN "Denominator" ON p.patient_id = "Denominator".patient_id LEFT JOIN "Denominator Exclusions" ON p.patient_id = "Denominator Exclusions".patient_id LEFT JOIN "Numerator" ON p.patient_id = "Numerator".patient_id ORDER BY p.patient_id ASC
